/**
 * TOPIC-INDEX.md regenerator — v12.5 Zone B projection.
 *
 * Output matches Jarvis's current format:
 *   # TOPIC-INDEX.md
 *
 *   Auto-generated by silo projection regenerator. Do not edit manually.
 *   Last generated: YYYY-MM-DD HH:MM:SS UTC
 *
 *   ```
 *   SLUG | TYPE | tag1,tag2,tag3 | STATUS | summary-first-sentence
 *   ```
 *
 * Target size: ~100-150 chars per entry. Auto-loaded by Jarvis every session.
 */

import yaml from 'js-yaml';

/**
 * Extract the first sentence from a summary string without being fooled by
 * decimals ("Voron 2.4") or abbreviations ("v3.x"). Strategy: find the first
 * `. !` or `?` followed by a space+uppercase or end-of-string.
 */
function firstSentence(summary) {
  if (!summary) return '';
  const trimmed = summary.trim();

  // Look for sentence terminator followed by whitespace + uppercase (new sentence),
  // or end of string.
  const match = trimmed.match(/^[\s\S]+?[.!?](?=\s+[A-Z]|\s*$)/);
  if (match) return match[0].trim();

  // No clean sentence boundary — return first line or first 160 chars
  const firstLine = trimmed.split('\n')[0].trim();
  return firstLine.length <= 160 ? firstLine : firstLine.slice(0, 160).trimEnd() + '…';
}

function indexLine(frontmatter) {
  const slug = frontmatter.topic;
  const type = frontmatter.type || 'reference';
  const tags = Array.isArray(frontmatter.tags) ? frontmatter.tags.join(',') : '';
  const status = frontmatter.status || 'active';
  const summary = firstSentence(frontmatter.summary);
  return `${slug} | ${type} | ${tags} | ${status} | ${summary}`;
}

function extractFrontmatter(topicFileText) {
  const match = topicFileText.match(/^---\n([\s\S]*?)\n---\n/);
  if (!match) return null;
  return yaml.load(match[1], { schema: yaml.JSON_SCHEMA });
}

/**
 * Format a timestamp like "2026-04-22 16:45:02 UTC" for the header line.
 */
function formatUtcTimestamp(date = new Date()) {
  const pad = (n) => String(n).padStart(2, '0');
  return (
    `${date.getUTCFullYear()}-${pad(date.getUTCMonth() + 1)}-${pad(date.getUTCDate())} ` +
    `${pad(date.getUTCHours())}:${pad(date.getUTCMinutes())}:${pad(date.getUTCSeconds())} UTC`
  );
}

/**
 * Regenerate TOPIC-INDEX.md content.
 *
 * @param {Map<string, string>} topicFiles - map slug -> regenerated file text
 * @param {Object} [opts]
 * @param {Date} [opts.generatedAt] - override timestamp (for deterministic tests)
 * @returns {string}
 */
export function regenerateTopicIndex(topicFiles, opts = {}) {
  const generatedAt = opts.generatedAt ?? new Date();
  const lines = [
    '# TOPIC-INDEX.md',
    '',
    'Auto-generated by silo projection regenerator. Do not edit manually.',
    `Last generated: ${formatUtcTimestamp(generatedAt)}`,
    '',
    '```',
  ];

  const slugs = [...topicFiles.keys()].sort();
  for (const slug of slugs) {
    const frontmatter = extractFrontmatter(topicFiles.get(slug));
    if (!frontmatter) continue;
    if (frontmatter.status === 'archived') continue;
    lines.push(indexLine(frontmatter));
  }

  lines.push('```');
  lines.push('');
  return lines.join('\n');
}
